+        )
+    };
+
+    Ok(DispatchOutcome {
+        payload: json!({
+            "status": status,
+            "command": "task",
+            "subcommand": "ask",
+            "message": message,
+            "question": task.resolution.pending_question,
+            "task": task_payload_view(&task),
+            "state_root": store.root_dir().display().to_string(),
+        }),
+        exit_code: ExitCode::SUCCESS,
+    })
+}
