+fn resolution_lookup_query(task: &WorkflowTask) -> Option<String> {
+    task.compiled
+        .lookup_literal
+        .as_deref()
+        .and_then(|lookup| split_append_lookup_payload(lookup).map(|(resolved, _)| resolved))
+        .or_else(|| {
+            task.compiled
+                .lookup_literal
+                .as_deref()
+                .map(trim_literal_fragment)
+                .filter(|lookup| !lookup.is_empty())
+        })
